			inputData:      []byte("unmatchedprefix:data"),
			prefixes: []PrefixTransformer{
				{Prefix: []byte("k8s:"), Transformer: &mockTransformer{decryptedData: []byte("value")}},
			},
			expectedErrMsg: "custom: no supported transformation found",
		},
		{
			name:           "default error when nil provided",
			customError:    nil,
			inputData:      []byte("noprefix:data"),
			prefixes: []PrefixTransformer{
				{Prefix: []byte("k8s:"), Transformer: &mockTransformer{decryptedData: []byte("value")}},
			},
			expectedErrMsg: "the provided value does not match any of the supported transformers",
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := context.Background()

			transformer := NewPrefixTransformers(tc.customError, tc.prefixes...)

			_, _, err := transformer.TransformFromStorage(ctx, tc.inputData, nil)

			if err == nil {
				t.Fatalf("expected error but got none")
			}

			if err.Error() != tc.expectedErrMsg {
