}

// TestStaleMarking tests that transformations not using the first transformer are marked as stale.
func TestStaleMarking(t *testing.T) {
	testCases := []struct {
		name            string
		transformerIdx  int
		expectedStale   bool
		description     string
	}{
		{
			name:           "first transformer not marked stale",
			transformerIdx: 0,
			expectedStale:  false,
			description:    "first transformer should not be marked stale",
		},
		{
			name:           "second transformer marked stale",
			transformerIdx: 1,
			expectedStale:  true,
			description:    "second transformer should be marked stale",
		},
		{
			name:           "third transformer marked stale",
			transformerIdx: 2,
			expectedStale:  true,
			description:    "third transformer should be marked stale",
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := context.Background()

			prefixes := []PrefixTransformer{
				{Prefix: []byte("first:"), Transformer: &mockTransformer{decryptedData: []byte("v1")}},
				{Prefix: []byte("second:"), Transformer: &mockTransformer{decryptedData: []byte("v2")}},
				{Prefix: []byte("third:"), Transformer: &mockTransformer{decryptedData: []byte("v3")}},
			}

			transformer := NewPrefixTransformers(fmt.Errorf("no match"), prefixes...)

			var inputData []byte
			switch tc.transformerIdx {
			case 0:
				inputData = []byte("first:encrypted")
			case 1:
				inputData = []byte("second:encrypted")
			case 2:
				inputData = []byte("third:encrypted")
			}

			_, stale, err := transformer.TransformFromStorage(ctx, inputData, nil)

			if err != nil {
				t.Errorf("unexpected error: %v", err)
			}

			if stale != tc.expectedStale {
				t.Errorf("%s: expected stale=%v, got %v", tc.description, tc.expectedStale, stale)
			}
		})
	}
}

// TestEmptyDataHandling tests handling of empty data in transformations.
func TestEmptyDataHandling(t *testing.T) {
	testCases := []struct {
		name           string
		prefix         []byte
		inputData      []byte
		decryptedData  []byte
		encryptedData  []byte
		shouldFail     bool
	}{
		{
			name:          "empty encrypted data with matching prefix",
			prefix:        []byte("k8s:"),
			inputData:     []byte("k8s:"),
			decryptedData: []byte{},
		},
		{
			name:          "empty plaintext to encrypt",
			prefix:        []byte("k8s:"),
			encryptedData: []byte("encrypted-empty"),
		},
		{
			name:        "no data at all",
			prefix:      []byte("k8s:"),
			inputData:   []byte(""),
			shouldFail:  true,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := context.Background()

			innerTransformer := &mockTransformer{
				decryptedData: tc.decryptedData,
				encryptedData: tc.encryptedData,
			}

			transformer := NewPrefixTransformers(
				fmt.Errorf("no matching prefix"),
				PrefixTransformer{Prefix: tc.prefix, Transformer: innerTransformer},
			)

			if tc.shouldFail {
				_, _, err := transformer.TransformFromStorage(ctx, tc.inputData, nil)
				if err == nil {
					t.Errorf("expected error for empty data")
				}
				return
			}

			// Test read path
			if tc.decryptedData != nil {
				result, _, err := transformer.TransformFromStorage(ctx, tc.inputData, nil)
				if err != nil {
					t.Errorf("unexpected error: %v", err)
				}
				if !bytes.Equal(result, tc.decryptedData) {
					t.Errorf("expected %v, got %v", tc.decryptedData, result)
				}
			}

			// Test write path
			if tc.encryptedData != nil {
				result, err := transformer.TransformToStorage(ctx, []byte{}, nil)
				if err != nil {
					t.Errorf("unexpected error: %v", err)
				}
				expected := append(tc.prefix, tc.encryptedData...)
				if !bytes.Equal(result, expected) {
					t.Errorf("expected %v, got %v", expected, result)
				}
			}
		})
	}
}

