// mockTransformer is a simple test transformer for unit testing.
type mockTransformer struct {
	encryptedData []byte
	decryptedData []byte
	err           error
	stale         bool
}

func (m *mockTransformer) TransformFromStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
	if m.err != nil {
		return nil, false, m.err
	}
	return m.decryptedData, m.stale, nil
}

func (m *mockTransformer) TransformToStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
	if m.err != nil {
		return nil, m.err
	}
	return m.encryptedData, nil
}

// TestDefaultContextAuthenticatedData tests that DefaultContext correctly returns authenticated data.
func TestDefaultContextAuthenticatedData(t *testing.T) {
	testCases := []struct {
		name     string
		data     []byte
		expected []byte
	}{
		{
			name:     "simple data",
			data:     []byte("test-data"),
			expected: []byte("test-data"),
		},
		{
			name:     "empty data",
			data:     []byte{},
			expected: []byte{},
		},
		{
			name:     "binary data",
			data:     []byte{0, 1, 2, 255},
			expected: []byte{0, 1, 2, 255},
		},
		{
			name:     "nil returns nil",
			data:     nil,
			expected: nil,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := DefaultContext(tc.data)
			result := ctx.AuthenticatedData()
			if !bytes.Equal(result, tc.expected) {
				t.Errorf("expected %v, got %v", tc.expected, result)
			}
		})
	}
}

// TestTransformerRoundTrip tests basic encrypt/decrypt round trip functionality.
func TestTransformerRoundTrip(t *testing.T) {
	testCases := []struct {
		name          string
		plaintext     []byte
		ciphertext    []byte
		encryptErr    error
		decryptErr    error
		shouldFail    bool
	}{
		{
			name:       "successful round trip",
			plaintext:  []byte("secret-data"),
			ciphertext: []byte("encrypted-secret-data"),
		},
		{
			name:       "empty plaintext",
			plaintext:  []byte{},
			ciphertext: []byte("encrypted-empty"),
		},
		{
			name:       "large plaintext",
			plaintext:  bytes.Repeat([]byte("x"), 10000),
			ciphertext: bytes.Repeat([]byte("y"), 10000),
		},
		{
			name:       "encrypt error",
			plaintext:  []byte("data"),
			encryptErr: fmt.Errorf("encryption failed"),
			shouldFail: true,
		},
		{
			name:       "decrypt error",
			ciphertext: []byte("encrypted"),
			decryptErr: fmt.Errorf("decryption failed"),
			shouldFail: true,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := context.Background()
			transformer := &mockTransformer{
				encryptedData: tc.ciphertext,
				decryptedData: tc.plaintext,
				err:           tc.encryptErr,
			}

			// Test ToStorage (encryption)
			encrypted, err := transformer.TransformToStorage(ctx, tc.plaintext, nil)
			if tc.encryptErr != nil {
				if err == nil {
					t.Errorf("expected encryption error")
				}
				return
			}
			if err != nil {
				t.Errorf("unexpected encryption error: %v", err)
			}
			if !bytes.Equal(encrypted, tc.ciphertext) {
				t.Errorf("encryption mismatch: expected %v, got %v", tc.ciphertext, encrypted)
			}

			// Test FromStorage (decryption)
			transformer.err = tc.decryptErr
			decrypted, _, err := transformer.TransformFromStorage(ctx, tc.ciphertext, nil)
			if tc.decryptErr != nil {
				if err == nil {
					t.Errorf("expected decryption error")
				}
				return
			}
			if err != nil {
				t.Errorf("unexpected decryption error: %v", err)
			}
			if !bytes.Equal(decrypted, tc.plaintext) {
				t.Errorf("decryption mismatch: expected %v, got %v", tc.plaintext, decrypted)
			}
		})
	}
}

// TestPrefixTransformerStripsPrefixOnRead tests that PrefixTransformer correctly strips the prefix during reads.
func TestPrefixTransformerStripsPrefixOnRead(t *testing.T) {
	testCases := []struct {
		name           string
		prefix         []byte
		prefixedData   []byte
		expectedData   []byte
		decryptedData  []byte
		shouldFail     bool
	}{
		{
			name:          "simple prefix strip",
			prefix:        []byte("k8s:enc:v1:"),
			prefixedData:  []byte("k8s:enc:v1:encrypted-content"),
			expectedData:  []byte("encrypted-content"),
			decryptedData: []byte("plaintext"),
		},
		{
			name:          "empty prefix",
			prefix:        []byte{},
			prefixedData:  []byte("encrypted-content"),
			expectedData:  []byte("encrypted-content"),
			decryptedData: []byte("plaintext"),
		},
		{
			name:          "prefix not matched",
			prefix:        []byte("wrong:prefix:"),
			prefixedData:  []byte("k8s:enc:v1:encrypted-content"),
			expectedData:  []byte{},
			decryptedData: []byte("plaintext"),
			shouldFail:    true,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := context.Background()
			innerTransformer := &mockTransformer{
				decryptedData: tc.decryptedData,
			}

			transformers := NewPrefixTransformers(
				fmt.Errorf("no matching prefix"),
				PrefixTransformer{Prefix: tc.prefix, Transformer: innerTransformer},
			)

			result, _, err := transformers.TransformFromStorage(ctx, tc.prefixedData, nil)

			if tc.shouldFail {
				if err == nil {
					t.Errorf("expected error for non-matching prefix")
				}
				return
			}

			if err != nil {
				t.Errorf("unexpected error: %v", err)
			}

			if !bytes.Equal(result, tc.decryptedData) {
				t.Errorf("expected %v, got %v", tc.decryptedData, result)
			}
		})
	}
}

// TestPrefixTransformerAddsPrefixOnWrite tests that PrefixTransformer correctly adds the prefix during writes.
func TestPrefixTransformerAddsPrefixOnWrite(t *testing.T) {
	testCases := []struct {
		name           string
		prefix         []byte
		plaintext      []byte
		encryptedData  []byte
		expectedOutput []byte
	}{
		{
			name:           "simple prefix addition",
			prefix:         []byte("k8s:enc:v1:"),
			plaintext:      []byte("secret"),
			encryptedData:  []byte("encrypted-secret"),
			expectedOutput: []byte("k8s:enc:v1:encrypted-secret"),
		},
		{
			name:           "empty prefix",
			prefix:         []byte{},
			plaintext:      []byte("secret"),
			encryptedData:  []byte("encrypted-secret"),
			expectedOutput: []byte("encrypted-secret"),
		},
		{
			name:           "large prefix",
			prefix:         []byte("k8s:enc:aescbc:v1:"),
			plaintext:      []byte("data"),
			encryptedData:  bytes.Repeat([]byte("x"), 1000),
			expectedOutput: append([]byte("k8s:enc:aescbc:v1:"), bytes.Repeat([]byte("x"), 1000)...),
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := context.Background()
			innerTransformer := &mockTransformer{
				encryptedData: tc.encryptedData,
			}

			transformers := NewPrefixTransformers(
				fmt.Errorf("no matching prefix"),
				PrefixTransformer{Prefix: tc.prefix, Transformer: innerTransformer},
			)

			result, err := transformers.TransformToStorage(ctx, tc.plaintext, nil)

			if err != nil {
				t.Errorf("unexpected error: %v", err)
			}

			if !bytes.Equal(result, tc.expectedOutput) {
				t.Errorf("expected %v, got %v", tc.expectedOutput, result)
			}
		})
	}
}

// TestPrefixTransformerUnionMultiplePrefixes tests the fanout-and-select behavior of TransformerUnion.
func TestPrefixTransformerUnionMultiplePrefixes(t *testing.T) {
	testCases := []struct {
		name              string
		prefixes          []PrefixTransformer
		inputData         []byte
		expectMatch       int
		expectStale       bool
		expectError       bool
		decryptedValues   map[int][]byte
	}{
		{
			name: "first prefix matches",
			prefixes: []PrefixTransformer{
				{Prefix: []byte("first:"), Transformer: &mockTransformer{decryptedData: []byte("value1")}},
				{Prefix: []byte("second:"), Transformer: &mockTransformer{decryptedData: []byte("value2")}},
			},
			inputData:   []byte("first:encrypted"),
			expectMatch: 0,
			expectStale: false,
			decryptedValues: map[int][]byte{
				0: []byte("value1"),
				1: []byte("value2"),
			},
		},
		{
			name: "second prefix matches",
			prefixes: []PrefixTransformer{
				{Prefix: []byte("first:"), Transformer: &mockTransformer{decryptedData: []byte("value1")}},
				{Prefix: []byte("second:"), Transformer: &mockTransformer{decryptedData: []byte("value2")}},
			},
			inputData:   []byte("second:encrypted"),
			expectMatch: 1,
			expectStale: true, // Should be marked stale because it's not the first transformer
			decryptedValues: map[int][]byte{
				0: []byte("value1"),
				1: []byte("value2"),
			},
		},
		{
			name: "no prefix matches",
			prefixes: []PrefixTransformer{
				{Prefix: []byte("first:"), Transformer: &mockTransformer{decryptedData: []byte("value1")}},
				{Prefix: []byte("second:"), Transformer: &mockTransformer{decryptedData: []byte("value2")}},
			},
			inputData:   []byte("third:encrypted"),
			expectError: true,
			decryptedValues: map[int][]byte{
				0: []byte("value1"),
				1: []byte("value2"),
			},
		},
		{
			name: "empty prefix (identity transformer) matches first",
			prefixes: []PrefixTransformer{
				{Prefix: []byte{}, Transformer: &mockTransformer{decryptedData: []byte("identity")}},
				{Prefix: []byte("enc:"), Transformer: &mockTransformer{decryptedData: []byte("encrypted")}},
			},
			inputData:   []byte("unencrypted"),
			expectMatch: 0,
			expectStale: false,
			decryptedValues: map[int][]byte{
				0: []byte("identity"),
				1: []byte("encrypted"),
			},
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := context.Background()
			transformer := NewPrefixTransformers(fmt.Errorf("no matching prefix"), tc.prefixes...)

			result, stale, err := transformer.TransformFromStorage(ctx, tc.inputData, nil)

			if tc.expectError {
				if err == nil {
					t.Errorf("expected error but got none")
				}
				return
			}

			if err != nil {
				t.Errorf("unexpected error: %v", err)
			}

			if stale != tc.expectStale {
				t.Errorf("stale mismatch: expected %v, got %v", tc.expectStale, stale)
			}

			expectedValue := tc.decryptedValues[tc.expectMatch]
			if !bytes.Equal(result, expectedValue) {
				t.Errorf("value mismatch: expected %v, got %v", expectedValue, result)
			}
		})
	}
}

// TestPrefixTransformerErrorHandlingWithOverlappingPrefixes tests error propagation for overlapping prefixes.
func TestPrefixTransformerErrorHandlingWithOverlappingPrefixes(t *testing.T) {
	testCases := []struct {
		name      string
		prefixes  []PrefixTransformer
		inputData []byte
		expectErr bool
		expectVal []byte
	}{
		{
			name: "first transformer errors, second succeeds with same prefix",
			prefixes: []PrefixTransformer{
				{
					Prefix: []byte("k8s:enc:aescbc:v1:"),
					Transformer: &mockTransformer{
						err: fmt.Errorf("key1 not found"),
					},
				},
				{
					Prefix: []byte("k8s:enc:aescbc:v1:"),
					Transformer: &mockTransformer{
						decryptedData: []byte("decrypted-with-key2"),
					},
				},
			},
			inputData: []byte("k8s:enc:aescbc:v1:encrypted"),
			expectErr: false,
			expectVal: []byte("decrypted-with-key2"),
		},
		{
			name: "all transformers fail with same prefix",
			prefixes: []PrefixTransformer{
				{
					Prefix: []byte("k8s:enc:aescbc:v1:"),
					Transformer: &mockTransformer{
						err: fmt.Errorf("key1 not found"),
					},
				},
				{
					Prefix: []byte("k8s:enc:aescbc:v1:"),
					Transformer: &mockTransformer{
						err: fmt.Errorf("key2 not found"),
					},
				},
			},
			inputData: []byte("k8s:enc:aescbc:v1:encrypted"),
			expectErr: true,
		},
		{
			name: "empty prefix (identity) errors, falls through to next",
			prefixes: []PrefixTransformer{
				{
					Prefix: []byte{},
					Transformer: &mockTransformer{
						err: fmt.Errorf("data is encrypted"),
					},
				},
				{
					Prefix: []byte("k8s:enc:"),
					Transformer: &mockTransformer{
						decryptedData: []byte("decrypted"),
					},
				},
			},
			inputData: []byte("k8s:enc:encrypted"),
			expectErr: false,
			expectVal: []byte("decrypted"),
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := context.Background()
			transformer := NewPrefixTransformers(fmt.Errorf("no matching prefix"), tc.prefixes...)

			result, _, err := transformer.TransformFromStorage(ctx, tc.inputData, nil)

			if tc.expectErr {
				if err == nil {
					t.Errorf("expected error but got none")
				}
				return
			}

			if err != nil {
				t.Errorf("unexpected error: %v", err)
			}

			if !bytes.Equal(result, tc.expectVal) {
				t.Errorf("value mismatch: expected %v, got %v", tc.expectVal, result)
			}
		})
	}
}

// TestPrefixTransformerAlwaysUsesFirstForWrite tests that TransformToStorage always uses the first transformer.
func TestPrefixTransformerAlwaysUsesFirstForWrite(t *testing.T) {
	testCases := []struct {
		name        string
		firstPrefix []byte
		otherPrefix []byte
		plaintext   []byte
		encrypted   []byte
	}{
		{
			name:        "multiple prefixes, always uses first",
			firstPrefix: []byte("new-key:"),
			otherPrefix: []byte("old-key:"),
			plaintext:   []byte("secret"),
			encrypted:   []byte("encrypted-with-new-key"),
		},
		{
			name:        "empty prefix first",
			firstPrefix: []byte{},
			otherPrefix: []byte("enc:"),
			plaintext:   []byte("data"),
			encrypted:   []byte("identity-encrypted"),
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := context.Background()

			firstTransformer := &mockTransformer{encryptedData: tc.encrypted}
			secondTransformer := &mockTransformer{
				encryptedData: []byte("should-not-be-used"),
			}

			transformers := NewPrefixTransformers(
				fmt.Errorf("no matching prefix"),
				PrefixTransformer{Prefix: tc.firstPrefix, Transformer: firstTransformer},
				PrefixTransformer{Prefix: tc.otherPrefix, Transformer: secondTransformer},
			)

			result, err := transformers.TransformToStorage(ctx, tc.plaintext, nil)

			if err != nil {
				t.Errorf("unexpected error: %v", err)
			}

			expectedOutput := append(tc.firstPrefix, tc.encrypted...)
			if !bytes.Equal(result, expectedOutput) {
				t.Errorf("expected %v, got %v", expectedOutput, result)
			}

			// Verify the second transformer was never called
			if len(secondTransformer.encryptedData) > 0 {
				t.Errorf("second transformer should not be used for writes")
			}
		})
	}
}

// TestPrefixTransformerWriteError tests error handling in TransformToStorage.
func TestPrefixTransformerWriteError(t *testing.T) {
	testCases := []struct {
		name      string
		prefix    []byte
		plaintext []byte
		err       error
	}{
		{
			name:      "encryption fails",
			prefix:    []byte("k8s:enc:v1:"),
			plaintext: []byte("secret"),
			err:       fmt.Errorf("encryption failed: key unavailable"),
		},
		{
			name:      "error with empty prefix",
			prefix:    []byte{},
			plaintext: []byte("data"),
			err:       fmt.Errorf("transformation error"),
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := context.Background()

			innerTransformer := &mockTransformer{err: tc.err}

			transformer := NewPrefixTransformers(
				fmt.Errorf("no matching prefix"),
				PrefixTransformer{Prefix: tc.prefix, Transformer: innerTransformer},
			)

			_, err := transformer.TransformToStorage(ctx, tc.plaintext, nil)

			if err == nil {
				t.Errorf("expected error but got none")
			}

			if err.Error() != tc.err.Error() {
				t.Errorf("expected error %v, got %v", tc.err, err)
			}
		})
	}
}

// TestContextInterfaceWithAuthenticatedData tests the Context interface behavior.
func TestContextInterfaceWithAuthenticatedData(t *testing.T) {
	testCases := []struct {
		name     string
		ctx      Context
		expected []byte
	}{
		{
			name:     "DefaultContext with data",
			ctx:      DefaultContext([]byte("key:version:1")),
			expected: []byte("key:version:1"),
