// mockTransformer is a simple test transformer for unit testing.
type mockTransformer struct {
	encryptedData []byte
	decryptedData []byte
	err           error
	stale         bool
}

func (m *mockTransformer) TransformFromStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, bool, error) {
	if m.err != nil {
		return nil, false, m.err
	}
	return m.decryptedData, m.stale, nil
}

func (m *mockTransformer) TransformToStorage(ctx context.Context, data []byte, dataCtx Context) ([]byte, error) {
	if m.err != nil {
		return nil, m.err
	}
	return m.encryptedData, nil
}

// TestDefaultContextAuthenticatedData tests that DefaultContext correctly returns authenticated data.
func TestDefaultContextAuthenticatedData(t *testing.T) {
	testCases := []struct {
		name     string
		data     []byte
		expected []byte
	}{
		{
			name:     "simple data",
			data:     []byte("test-data"),
			expected: []byte("test-data"),
		},
		{
			name:     "empty data",
			data:     []byte{},
			expected: []byte{},
		},
		{
			name:     "binary data",
			data:     []byte{0, 1, 2, 255},
			expected: []byte{0, 1, 2, 255},
		},
		{
			name:     "nil returns nil",
			data:     nil,
			expected: nil,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := DefaultContext(tc.data)
			result := ctx.AuthenticatedData()
			if !bytes.Equal(result, tc.expected) {
				t.Errorf("expected %v, got %v", tc.expected, result)
			}
		})
	}
}

// TestTransformerRoundTrip tests basic encrypt/decrypt round trip functionality.
func TestTransformerRoundTrip(t *testing.T) {
	testCases := []struct {
		name          string
		plaintext     []byte
		ciphertext    []byte
		encryptErr    error
		decryptErr    error
		shouldFail    bool
	}{
		{
			name:       "successful round trip",
			plaintext:  []byte("secret-data"),
			ciphertext: []byte("encrypted-secret-data"),
		},
		{
			name:       "empty plaintext",
			plaintext:  []byte{},
			ciphertext: []byte("encrypted-empty"),
		},
		{
			name:       "large plaintext",
			plaintext:  bytes.Repeat([]byte("x"), 10000),
			ciphertext: bytes.Repeat([]byte("y"), 10000),
		},
		{
			name:       "encrypt error",
			plaintext:  []byte("data"),
			encryptErr: fmt.Errorf("encryption failed"),
			shouldFail: true,
		},
		{
			name:       "decrypt error",
			ciphertext: []byte("encrypted"),
			decryptErr: fmt.Errorf("decryption failed"),
			shouldFail: true,
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := context.Background()
			transformer := &mockTransformer{
				encryptedData: tc.ciphertext,
				decryptedData: tc.plaintext,
				err:           tc.encryptErr,
			}

			// Test ToStorage (encryption)
			encrypted, err := transformer.TransformToStorage(ctx, tc.plaintext, nil)
			if tc.encryptErr != nil {
				if err == nil {
					t.Errorf("expected encryption error")
				}
				return
			}
			if err != nil {
				t.Errorf("unexpected encryption error: %v", err)
			}
			if !bytes.Equal(encrypted, tc.ciphertext) {
				t.Errorf("encryption mismatch: expected %v, got %v", tc.ciphertext, encrypted)
			}

			// Test FromStorage (decryption)
			transformer.err = tc.decryptErr
			decrypted, _, err := transformer.TransformFromStorage(ctx, tc.ciphertext, nil)
			if tc.decryptErr != nil {
				if err == nil {
					t.Errorf("expected decryption error")
				}
				return
			}
			if err != nil {
				t.Errorf("unexpected decryption error: %v", err)
			}
			if !bytes.Equal(decrypted, tc.plaintext) {
				t.Errorf("decryption mismatch: expected %v, got %v", tc.plaintext, decrypted)
			}
		})
	}
}

// TestPrefixTransformerStripsPrefixOnRead tests that PrefixTransformer correctly strips the prefix during reads.
