	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := context.Background()
			transformer := NewPrefixTransformers(fmt.Errorf("no matching prefix"), tc.prefixes...)

			result, _, err := transformer.TransformFromStorage(ctx, tc.inputData, nil)

			if tc.expectErr {
				if err == nil {
					t.Errorf("expected error but got none")
				}
				return
			}

			if err != nil {
				t.Errorf("unexpected error: %v", err)
			}

			if !bytes.Equal(result, tc.expectVal) {
				t.Errorf("value mismatch: expected %v, got %v", tc.expectVal, result)
			}
		})
	}
}

// TestPrefixTransformerAlwaysUsesFirstForWrite tests that TransformToStorage always uses the first transformer.
func TestPrefixTransformerAlwaysUsesFirstForWrite(t *testing.T) {
	testCases := []struct {
		name        string
		firstPrefix []byte
		otherPrefix []byte
		plaintext   []byte
		encrypted   []byte
	}{
		{
			name:        "multiple prefixes, always uses first",
			firstPrefix: []byte("new-key:"),
			otherPrefix: []byte("old-key:"),
			plaintext:   []byte("secret"),
			encrypted:   []byte("encrypted-with-new-key"),
		},
		{
			name:        "empty prefix first",
			firstPrefix: []byte{},
			otherPrefix: []byte("enc:"),
			plaintext:   []byte("data"),
			encrypted:   []byte("identity-encrypted"),
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := context.Background()

			firstTransformer := &mockTransformer{encryptedData: tc.encrypted}
			secondTransformer := &mockTransformer{
				encryptedData: []byte("should-not-be-used"),
			}

			transformers := NewPrefixTransformers(
				fmt.Errorf("no matching prefix"),
				PrefixTransformer{Prefix: tc.firstPrefix, Transformer: firstTransformer},
				PrefixTransformer{Prefix: tc.otherPrefix, Transformer: secondTransformer},
			)

			result, err := transformers.TransformToStorage(ctx, tc.plaintext, nil)

			if err != nil {
				t.Errorf("unexpected error: %v", err)
			}

			expectedOutput := append(tc.firstPrefix, tc.encrypted...)
			if !bytes.Equal(result, expectedOutput) {
				t.Errorf("expected %v, got %v", expectedOutput, result)
			}

			// Verify the second transformer was never called
			if len(secondTransformer.encryptedData) > 0 {
				t.Errorf("second transformer should not be used for writes")
			}
		})
	}
}

// TestPrefixTransformerWriteError tests error handling in TransformToStorage.
func TestPrefixTransformerWriteError(t *testing.T) {
	testCases := []struct {
		name      string
		prefix    []byte
		plaintext []byte
		err       error
	}{
		{
			name:      "encryption fails",
			prefix:    []byte("k8s:enc:v1:"),
			plaintext: []byte("secret"),
			err:       fmt.Errorf("encryption failed: key unavailable"),
		},
		{
			name:      "error with empty prefix",
			prefix:    []byte{},
			plaintext: []byte("data"),
			err:       fmt.Errorf("transformation error"),
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := context.Background()

			innerTransformer := &mockTransformer{err: tc.err}

			transformer := NewPrefixTransformers(
