// TestPrefixTransformerWithContextData tests that context data is properly propagated through transformations.
func TestPrefixTransformerWithContextData(t *testing.T) {
	testCases := []struct {
		name          string
		prefix        []byte
		prefixedData  []byte
		contextData   []byte
		decryptedData []byte
	}{
		{
			name:          "context authenticated data passed through",
			prefix:        []byte("k8s:"),
			prefixedData:  []byte("k8s:encrypted"),
			contextData:   []byte("key:version:1"),
			decryptedData: []byte("plaintext"),
		},
		{
			name:          "empty context data",
			prefix:        []byte("enc:"),
			prefixedData:  []byte("enc:data"),
			contextData:   []byte{},
			decryptedData: []byte("result"),
		},
	}

	for _, tc := range testCases {
		t.Run(tc.name, func(t *testing.T) {
			ctx := context.Background()
			dataCtx := DefaultContext(tc.contextData)

			innerTransformer := &mockTransformer{
				decryptedData: tc.decryptedData,
			}

			transformer := NewPrefixTransformers(
				fmt.Errorf("no matching prefix"),
				PrefixTransformer{Prefix: tc.prefix, Transformer: innerTransformer},
			)

			result, _, err := transformer.TransformFromStorage(ctx, tc.prefixedData, dataCtx)

			if err != nil {
				t.Errorf("unexpected error: %v", err)
			}

			if !bytes.Equal(result, tc.decryptedData) {
				t.Errorf("expected %v, got %v", tc.decryptedData, result)
			}

			if dataCtx.AuthenticatedData() != nil && !bytes.Equal(dataCtx.AuthenticatedData(), tc.contextData) {
				t.Errorf("context data should be unchanged")
			}
		})
	}
}

